#include <stdio.h>
#include <stdint.h>

/* Example 1: Hardware register polling */
#define STATUS_REG (*(volatile uint32_t *)0x40001000)
#define DATA_REG   (*(volatile uint32_t *)0x40001004)
#define BUSY_BIT   (1U << 0)

void wait_for_ready(void) {
    /* Without volatile, compiler may optimize this to:
       if (STATUS_REG & BUSY_BIT) while(1); */
    while (STATUS_REG & BUSY_BIT)
        ; /* spin until hardware clears BUSY */
}

/* Example 2: ISR-shared variable */
volatile int data_ready = 0;
volatile uint8_t rx_buffer[64];

/* Called from interrupt context */
void UART_ISR(void) {
    /* Read hardware, fill buffer */
    rx_buffer[0] = DATA_REG & 0xFF;
    data_ready = 1; /* Signal main loop */
}

void main_loop(void) {
    while (1) {
        /* Without volatile, compiler may read data_ready once
           and never re-check it */
        if (data_ready) {
            /* Process rx_buffer */
            data_ready = 0;
        }
    }
}

/* Example 3: Volatile pointer to non-volatile data vs
   non-volatile pointer to volatile data */
void pointer_qualifiers(void) {
    volatile uint32_t *hw_reg;  /* pointer to volatile data */
    /* Reads through hw_reg always go to memory */

    uint32_t * volatile ptr;     /* volatile pointer to non-volatile data */
    /* The pointer itself may change (e.g., DMA updates it) */
}

