    /* Demonstrate volatile prevents optimization */
    volatile int sensor_value = 0;
    /* This loop will re-read sensor_value each iteration */
    while (sensor_value == 0) {
        /* In real embedded code, hardware changes sensor_value */
        break; /* for demo only */
    }
    return 0;
}

