#include <stdint.h>

/* Simulated hardware registers */
#define TIM2_SR    (*(volatile uint32_t *)0x40000010)
#define TIM2_SR_UIF  (1U << 0) /* Update interrupt flag */

#define UART1_DR   (*(volatile uint32_t *)0x40011004)
#define UART1_SR   (*(volatile uint32_t *)0x40011000)
#define UART_RXNE  (1U << 5)

/* --- Shared state (volatile!) --- */
volatile uint8_t rx_buf[128];
volatile uint8_t rx_head = 0;
volatile uint8_t timer_tick = 0;

/* --- Timer ISR (ARM Cortex-M style) --- */
void TIM2_IRQHandler(void) {
    if (TIM2_SR & TIM2_SR_UIF) {
        TIM2_SR &= ~TIM2_SR_UIF; /* MUST clear flag first */
        timer_tick = 1;           /* Signal main loop */
        /* Do NOT call printf, malloc, etc. here! */
    }
}

/* --- UART Receive ISR --- */
void USART1_IRQHandler(void) {
    if (UART1_SR & UART_RXNE) {
        uint8_t data = (uint8_t)(UART1_DR & 0xFF); /* reading DR clears RXNE */
        rx_buf[rx_head] = data;
        rx_head = (rx_head + 1) % sizeof(rx_buf); /* circular buffer */
    }
}

/* --- Main loop processes data set by ISR --- */
void main_loop(void) {
    static uint8_t rx_tail = 0;

    while (1) {
        /* Process timer tick */
        if (timer_tick) {
            timer_tick = 0;
            /* Update display, toggle LED, etc. */
        }

        /* Process received UART data */
        while (rx_tail != rx_head) {
            uint8_t byte = rx_buf[rx_tail];
            rx_tail = (rx_tail + 1) % sizeof(rx_buf);
            /* process byte */
            (void)byte;
        }
    }
}

/* --- Critical section: disable interrupts for atomic access --- */
static inline void disable_interrupts(void) {
    /* ARM: __disable_irq(); or asm volatile("cpsid i"); */
}

static inline void enable_interrupts(void) {
    /* ARM: __enable_irq(); or asm volatile("cpsie i"); */
}

void safe_read_shared_data(uint32_t *dest, volatile uint32_t *src) {
    disable_interrupts();
    *dest = *src; /* atomic with respect to ISR */
    enable_interrupts();
}

volatile uint8_t flag = 0;

void TIM2_IRQHandler(void) {
    TIM2_SR &= ~(1U << 0); /* clear interrupt flag */
    flag = 1;               /* signal main loop */
}

void main_loop(void) {
    while (1) {
        if (flag) { flag = 0; /* process */ }
    }
}

#include <stdio.h>
#include <stdint.h>

/* Bit manipulation macros */
#define BIT(n)           (1U << (n))
#define SET_BIT(r, n)    ((r) |= BIT(n))
#define CLR_BIT(r, n)    ((r) &= ~BIT(n))
#define TGL_BIT(r, n)    ((r) ^= BIT(n))
#define GET_BIT(r, n)    (((r) >> (n)) & 1U)

/* Multi-bit field macros */
#define SET_FIELD(reg, mask, shift, val) \
    do { (reg) = ((reg) & ~((mask) << (shift))) | \
                 (((val) & (mask)) << (shift)); } while(0)

/* Example: GPIO MODER register (2 bits per pin) */
#define MODER_MASK  0x3U    /* 2-bit field */
#define MODER_INPUT  0x0U
#define MODER_OUTPUT 0x1U
#define MODER_AF     0x2U
#define MODER_ANALOG 0x3U

int main(void) {
    uint32_t reg = 0;

    /* Set bit 5 */
    SET_BIT(reg, 5);
    printf("After SET bit 5:    0x%08X\n", reg); /* 0x00000020 */

    /* Set bit 3 */
    SET_BIT(reg, 3);
    printf("After SET bit 3:    0x%08X\n", reg); /* 0x00000028 */

    /* Clear bit 5 */
    CLR_BIT(reg, 5);
    printf("After CLR bit 5:    0x%08X\n", reg); /* 0x00000008 */

    /* Toggle bit 3 */
    TGL_BIT(reg, 3);
    printf("After TGL bit 3:    0x%08X\n", reg); /* 0x00000000 */

    /* Multi-bit field: set pin 5 to output mode (bits 11:10 = 01) */
    uint32_t moder = 0;
    SET_FIELD(moder, MODER_MASK, 10, MODER_OUTPUT);
    printf("MODER pin5=output:  0x%08X\n", moder); /* 0x00000400 */

    /* Set pin 3 to analog mode (bits 7:6 = 11) */
    SET_FIELD(moder, MODER_MASK, 6, MODER_ANALOG);
    printf("MODER +pin3=analog: 0x%08X\n", moder); /* 0x000004C0 */

    /* Check if pin 5 is output */
    uint32_t pin5_mode = (moder >> 10) & MODER_MASK;
    printf("Pin 5 mode: %u (1=output)\n", pin5_mode);

    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <string.h>

/* Detect endianness at runtime */
int is_little_endian(void) {
    uint32_t x = 1;
    return *(uint8_t *)&x == 1;
}

/* Manual byte swap */
uint16_t swap16(uint16_t x) {
    return (x >> 8) | (x << 8);
}

uint32_t swap32(uint32_t x) {
    return ((x & 0xFF000000U) >> 24) |
           ((x & 0x00FF0000U) >> 8)  |
           ((x & 0x0000FF00U) << 8)  |
           ((x & 0x000000FFU) << 24);
}

/* Safe portable read: always works regardless of endianness */
uint32_t read_be32(const uint8_t *buf) {
    return ((uint32_t)buf[0] << 24) |
           ((uint32_t)buf[1] << 16) |
           ((uint32_t)buf[2] << 8)  |
           ((uint32_t)buf[3]);
}

void write_be32(uint8_t *buf, uint32_t val) {
    buf[0] = (val >> 24) & 0xFF;
    buf[1] = (val >> 16) & 0xFF;
    buf[2] = (val >> 8)  & 0xFF;
    buf[3] = val & 0xFF;
}

int main(void) {
    printf("System is %s-endian\n",
           is_little_endian() ? "little" : "big");

    /* Show byte layout */
    uint32_t val = 0x12345678;
    uint8_t *bytes = (uint8_t *)&val;
    printf("0x%08X in memory: %02X %02X %02X %02X\n",
           val, bytes[0], bytes[1], bytes[2], bytes[3]);
    /* Little-endian: 78 56 34 12 */
    /* Big-endian:    12 34 56 78 */

    /* Byte swap */
    uint32_t swapped = swap32(val);
    printf("Swapped: 0x%08X\n", swapped); /* 0x78563412 */

    /* GCC built-in (preferred) */
    uint32_t gcc_swapped = __builtin_bswap32(val);
    printf("GCC swap: 0x%08X\n", gcc_swapped); /* 0x78563412 */

    /* Portable big-endian read from byte buffer */
    uint8_t net_data[] = {0x12, 0x34, 0x56, 0x78};
    uint32_t host_val = read_be32(net_data);
    printf("From network: 0x%08X\n", host_val); /* 0x12345678 */

    return 0;
}

