#include <stdio.h>
#include <stdint.h>
#include <stddef.h>

/* Normal struct (with padding) */
struct normal {
    uint8_t  a;   /* offset 0, size 1 */
    /* 3 bytes padding */
    uint32_t b;   /* offset 4, size 4 */
    uint8_t  c;   /* offset 8, size 1 */
    /* 3 bytes padding */
};  /* total: 12 bytes */

/* Packed struct (no padding) */
struct __attribute__((packed)) packed {
    uint8_t  a;   /* offset 0 */
    uint32_t b;   /* offset 1 (misaligned!) */
    uint8_t  c;   /* offset 5 */
};  /* total: 6 bytes */

/* Alternative: #pragma pack */
#pragma pack(push, 1)
struct packed_pragma {
    uint8_t  a;
    uint32_t b;
    uint8_t  c;
};
#pragma pack(pop)

/* Network protocol header example */
struct __attribute__((packed)) ip_header {
    uint8_t  ver_ihl;     /* version + IHL */
    uint8_t  tos;         /* type of service */
    uint16_t total_len;   /* total length (big-endian) */
    uint16_t id;          /* identification */
    uint16_t frag_off;    /* fragment offset */
    uint8_t  ttl;         /* time to live */
    uint8_t  protocol;    /* protocol (6=TCP, 17=UDP) */
    uint16_t checksum;    /* header checksum */
    uint32_t src_addr;    /* source IP */
    uint32_t dst_addr;    /* destination IP */
};

int main(void) {
    printf("sizeof(normal): %zu\n", sizeof(struct normal));  /* 12 */
    printf("sizeof(packed): %zu\n", sizeof(struct packed));  /* 6 */
    printf("sizeof(packed_pragma): %zu\n", sizeof(struct packed_pragma)); /* 6 */
    printf("sizeof(ip_header): %zu\n", sizeof(struct ip_header)); /* 20 */

    /* Show offsets */
    printf("normal.b offset: %zu\n", offsetof(struct normal, b));  /* 4 */
    printf("packed.b offset: %zu\n", offsetof(struct packed, b));  /* 1 */

    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <string.h>

/* --- Static allocation (preferred in embedded) --- */
#define MAX_SENSORS 8
#define BUF_SIZE 256

static uint16_t sensor_data[MAX_SENSORS]; /* always available */
static char uart_rx_buf[BUF_SIZE];        /* always available */

/* --- Memory pool allocator --- */
#define POOL_BLOCK_SIZE 32
#define POOL_BLOCK_COUNT 16

typedef struct pool_block {
    struct pool_block *next;
    uint8_t data[POOL_BLOCK_SIZE - sizeof(struct pool_block *)];
} pool_block_t;

static pool_block_t pool_storage[POOL_BLOCK_COUNT];
static pool_block_t *pool_free_list = NULL;

void pool_init(void) {
    pool_free_list = NULL;
    for (int i = POOL_BLOCK_COUNT - 1; i >= 0; i--) {
        pool_storage[i].next = pool_free_list;
        pool_free_list = &pool_storage[i];
    }
}

void *pool_alloc(void) {
    if (pool_free_list == NULL) return NULL; /* pool exhausted */
    pool_block_t *block = pool_free_list;
    pool_free_list = block->next;
    return block;
}

void pool_free(void *ptr) {
    if (ptr == NULL) return;
    pool_block_t *block = (pool_block_t *)ptr;
    block->next = pool_free_list;
    pool_free_list = block;
}

/* --- Arena allocator (bump allocator) --- */
#define ARENA_SIZE 4096
static uint8_t arena_buf[ARENA_SIZE];
static size_t arena_offset = 0;

void *arena_alloc(size_t size) {
    /* Align to 4 bytes */
    size = (size + 3) & ~3U;
    if (arena_offset + size > ARENA_SIZE) return NULL;
    void *ptr = &arena_buf[arena_offset];
    arena_offset += size;
    return ptr;
}

void arena_reset(void) {
    arena_offset = 0; /* free everything at once */
}

int main(void) {
    /* Pool allocator demo */
    pool_init();
    void *a = pool_alloc();
    void *b = pool_alloc();
    printf("Pool alloc a=%p, b=%p\n", a, b);
    pool_free(a);
    void *c = pool_alloc(); /* reuses a's block */
    printf("Pool alloc c=%p (reused)\n", c);
    pool_free(b);
    pool_free(c);

    /* Arena allocator demo */
    int *x = arena_alloc(sizeof(int));
    *x = 42;
    char *s = arena_alloc(16);
    strcpy(s, "hello");
    printf("Arena: x=%d, s=%s\n", *x, s);
    arena_reset(); /* free all at once */

    return 0;
}

