#include <stdio.h>
#include <stdint.h>

/* Q16.16 fixed-point: 16 integer bits, 16 fractional bits */
typedef int32_t fixed_t;
#define FRAC_BITS 16
#define FIXED_ONE (1 << FRAC_BITS) /* 65536 = represents 1.0 */

/* Convert float to fixed */
fixed_t float_to_fixed(double f) {
    return (fixed_t)(f * FIXED_ONE);
}

/* Convert fixed to float (for display) */
double fixed_to_float(fixed_t f) {
    return (double)f / FIXED_ONE;
}

/* Multiply two fixed-point numbers */
fixed_t fixed_mul(fixed_t a, fixed_t b) {
    /* Use 64-bit intermediate to prevent overflow */
    return (fixed_t)(((int64_t)a * b) >> FRAC_BITS);
}

/* Divide two fixed-point numbers */
fixed_t fixed_div(fixed_t a, fixed_t b) {
    return (fixed_t)(((int64_t)a << FRAC_BITS) / b);
}

int main(void) {
    fixed_t a = float_to_fixed(3.14159);
    fixed_t b = float_to_fixed(2.0);

    printf("a = %.5f (raw: %d)\n", fixed_to_float(a), a);
    printf("b = %.5f (raw: %d)\n", fixed_to_float(b), b);

    /* Addition: direct integer add */
    fixed_t sum = a + b;
    printf("a + b = %.5f\n", fixed_to_float(sum)); /* ~5.14159 */

    /* Multiplication */
    fixed_t product = fixed_mul(a, b);
    printf("a * b = %.5f\n", fixed_to_float(product)); /* ~6.28318 */

    /* Division */
    fixed_t quotient = fixed_div(a, b);
    printf("a / b = %.5f\n", fixed_to_float(quotient)); /* ~1.57080 */

    /* Temperature example: 23.5 degrees */
    fixed_t temp = float_to_fixed(23.5);
    fixed_t scale = float_to_fixed(1.8);
    fixed_t offset = float_to_fixed(32.0);
    fixed_t fahrenheit = fixed_mul(temp, scale) + offset;
    printf("%.1f C = %.1f F\n",
           fixed_to_float(temp), fixed_to_float(fahrenheit));
    /* 23.5 C = 74.3 F */

    return 0;
}

