#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>

/* Power-of-2 size for fast modulo */
#define RING_SIZE 64  /* must be power of 2 */
#define RING_MASK (RING_SIZE - 1)

typedef struct {
    uint8_t buffer[RING_SIZE];
    volatile uint8_t head; /* write index (producer/ISR) */
    volatile uint8_t tail; /* read index  (consumer/main) */
} ring_buf_t;

void ring_init(ring_buf_t *rb) {
    rb->head = 0;
    rb->tail = 0;
}

bool ring_is_empty(const ring_buf_t *rb) {
    return rb->head == rb->tail;
}

bool ring_is_full(const ring_buf_t *rb) {
    return ((rb->head + 1) & RING_MASK) == rb->tail;
}

uint8_t ring_count(const ring_buf_t *rb) {
    return (rb->head - rb->tail) & RING_MASK;
}

/* Producer (called from ISR) */
bool ring_put(ring_buf_t *rb, uint8_t byte) {
    uint8_t next = (rb->head + 1) & RING_MASK;
    if (next == rb->tail) return false; /* full */
    rb->buffer[rb->head] = byte;
    rb->head = next;
    return true;
}

/* Consumer (called from main loop) */
bool ring_get(ring_buf_t *rb, uint8_t *byte) {
    if (rb->head == rb->tail) return false; /* empty */
    *byte = rb->buffer[rb->tail];
    rb->tail = (rb->tail + 1) & RING_MASK;
    return true;
}

int main(void) {
    ring_buf_t uart_rx;
    ring_init(&uart_rx);

    /* Simulate ISR pushing data */
    ring_put(&uart_rx, 'H');
    ring_put(&uart_rx, 'i');
    ring_put(&uart_rx, '!');

    printf("Count: %d\n", ring_count(&uart_rx)); /* 3 */

    /* Main loop consuming data */
    uint8_t ch;
    while (ring_get(&uart_rx, &ch)) {
        printf("Got: %c\n", ch);
    }
    /* Output: H, i, ! */

    printf("Empty: %d\n", ring_is_empty(&uart_rx)); /* 1 */

    return 0;
}

#define SIZE 64
#define MASK (SIZE - 1)
uint8_t buf[SIZE];
volatile uint8_t head = 0, tail = 0;

bool put(uint8_t b) {
    uint8_t next = (head + 1) & MASK;
    if (next == tail) return false; /* full */
    buf[head] = b;
    head = next;
    return true;
}

bool get(uint8_t *b) {
    if (head == tail) return false; /* empty */
    *b = buf[tail];
    tail = (tail + 1) & MASK;
    return true;
}
